class SensorDataService:
    """Helper class for multi-sensor data"""
    def __init__(self, ble_device):
        self.ble = ble_device
        
    def update_temperature(self, temp):
        """Send temperature data (Celsius)"""
        self.ble.set_sensor_value(temp)
        
    def update_humidity(self, humidity):
        """Send humidity data (percentage)"""
        self.ble.set_sensor_value(humidity)
        
    def update_multiple(self, values):
        """Send multiple sensor values as bytes"""
        if isinstance(values, dict):
            data = struct.pack('<ffff', 
                             values.get('temp', 0.0),
                             values.get('humidity', 0.0),
                             values.get('pressure', 0.0),
                             values.get('light', 0.0))
            self.ble.set_sensor_value(data)
        

class ControlCommandHandler:
    """Helper class for handling control commands"""
    CMD_OFF = 0x00
    CMD_ON = 0x01
    CMD_TOGGLE = 0x02
    CMD_SET_LEVEL = 0x03
    CMD_RESET = 0xFF
    
    def __init__(self):
        self._handlers = {}
        
    def register(self, command, handler):
        """Register a handler for a specific command"""
        self._handlers[command] = handler
        
    def handle(self, data):
        """Process received command data"""
        if len(data) == 0:
            return
            
        cmd = data[0]
        params = data[1:] if len(data) > 1 else b''
        
        if cmd in self._handlers:
            self._handlers[cmd](params)
        else:
            print(f"Unknown command: {cmd}")


